&quot;); } bigInteger operator + (const bigInteger &amp;A) const { bigInteger ret; ret.init(); int carry = 0,tmp; for(int i=0;i&lt;A.size || i &lt; size;i ++){ if(symbol == 1 &amp;&amp; A.symbol == 1) tmp = A.digit[i] + digit[i] + carry; else if(symbol == 1 &amp;&amp; A.symbol == 0) tmp = -digit[i] + A.digit[i] + carry; else if(symbol == 0 &amp;&amp; A.symbol == 1) tmp = digit[i] - A.digit[i] + carry; else tmp = -digit[i] - A.digit[i] + carry; carry = tmp / 10000; tmp %= 10000; tmp = tmp &gt; 0? tmp:-tmp; ret.digit[ret.size ++] = tmp; } if(carry != 0){ ret.digit[ret.size ++] = carry; if(carry &lt; 0) ret.symbol = 1; else ret.symbol = 0; return ret; } } }a,b,c; char str1[1002],str2[1002]; int main(){ while(scanf(&quot;%s%s&quot;,str1,str2) != EOF){ a.set(str1);b.set(str2); c = a + b; c.output(); } return 0; } #include &lt;stdio.h&gt; struct bigInteger{ int digit[1000]; int size; void init(){ for(int i=0;i&lt;1000;i++) digit[i] = 0; size = 0; } void set(int x){ init(); do{ digit[size ++] = x % 10000; x /= 10000; }while(x != 0); } void output(){ for(int i=size-1;i&gt;=0;i--){ if(i != size - 1) printf(&quot;%04d&quot;,digit[i]); else printf(&quot;%d&quot;,digit[i]); } printf(&quot;
&quot;); } bigInteger operator * (int x) const { bigInteger ret; ret.init(); int carry = 0; for(int i=0;i&lt;size;i++){ int tmp = digit[i] * x + carry; carry = tmp / 10000; tmp %= 10000; ret.digit[ret.size ++] = tmp; } if(carry != 0){ ret.digit[ret.size ++] = carry; } return ret; } }a; int main(){ int n; while(scanf(&quot;%d&quot;,&amp;n) != EOF){ a.init(); a.set(1); for(int i=1;i&lt;=n;i++) a = a * i; a.output(); } return 0; } 高精度进制转换#include &lt;stdio.h&gt; #include &lt;string.h&gt; #define maxDigits 1000 struct bigInteger{ int digit[1000]; int size; void init(){ for(int i=0;i&lt;1000;i++) digit[i] = 0; size = 0; } void set(int x){ init(); do{ digit[size ++] = x % 10000; x /= 10000; }while(x != 0); } void output(){ for(int i=size-1;i&gt;=0;i--){ if(i != size - 1) printf(&quot;%04d&quot;,digit[i]); else printf(&quot;%d&quot;,digit[i]); } printf(&quot;
&quot;); } bigInteger operator * (int x) const { bigInteger ret; ret.init(); int carry = 0; for(int i=0;i&lt;size;i++){ int tmp = digit[i] * x + carry; carry = tmp / 10000; tmp %= 10000; ret.digit[ret.size ++] = tmp; } if(carry != 0){ ret.digit[ret.size ++] = carry; } return ret; } bigInteger operator + (const bigInteger &amp;A) const{ bigInteger ret; ret.init(); int carry = 0; for(int i=0;i&lt;A.size || i &lt; size ;i++){ int tmp = A.digit[i] + digit[i] + carry; carry = tmp / 10000; tmp %= 10000; ret.digit[ret.size ++] = tmp; } if(carry != 0){ ret.digit[ret.size++] = carry; } return ret; } bigInteger operator / (int x) const { bigInteger ret; ret.init(); int remainer = 0; for(int i =size -1;i&gt;=0;i--){ int t = (remainer * 10000 + digit[i]) / x; int r = (remainer * 10000 + digit[i]) % x; ret.digit[i] = t; remainer = r; } ret.size = 0; for(int i=0;i &lt; maxDigits;i ++){ if(digit[i] != 0) ret.size = i; } ret.size ++; return ret; } int operator % (int x) const{ int remainer = 0; for(int i = size - 1;i&gt;=0;i--){ int t = (remainer * 10000 + digit[i]) / x; int r = (remainer * 10000 + digit[i]) % x; remainer = r; } return remainer; } }a,b,c; char str[10000]; char ans[10000]; int main(){ int m,n; while(scanf(&quot;%d%d&quot;,&amp;m,&amp;n) != EOF){ scanf(&quot;%s&quot;,str); int L = strlen(str); a.set(0); b.set(1); for(int i=L - 1;i&gt;= 0;i--){ int t; if(str[i] &gt;= &apos;0&apos; &amp;&amp; str[i] &lt;= &apos;9&apos;){ t = str[i] - &apos;0&apos;; } else t =str[i] - &apos;A&apos; + 10; a = a + b * t; b = b * m; } int size = 0; do{ int t = a % n; if(t &gt;= 10) ans[size ++] = t- 10 + &apos;a&apos;; else ans[size ++] = t + &apos;0&apos;; a = a / n; }while(a.digit[0] != 0 || a.size != 1); for(int i = size - 1;i &gt;= 0;i -- ) printf(&quot;%c&quot;,ans[i]); printf(&quot;
